<template>
  <div v-if="isConnected" class="flex flex-col space-y-2 p-3 bg-[#1a4f98] rounded-xl border border-[#4f86cb] transition-all">
    <div class="flex items-center justify-between text-xs font-medium text-gray-500 dark:text-slate-400">
      <span>Cast Volume</span>
      <span>{{ Math.round(volumeLevel * 100) }}%</span>
    </div>
    <div class="flex items-center space-x-2">
      <button 
        @click="toggleMute" 
        class="p-1 text-blue-100 hover:text-white transition-colors rounded-md hover:bg-[#2d6fbc] focus:outline-none"
        :title="isMuted ? 'Unmute' : 'Mute'"
      >
        <SpeakerXMarkIcon v-if="isMuted" class="w-5 h-5" />
        <SpeakerWaveIcon v-else class="w-5 h-5" />
      </button>
      
      <input
        type="range"
        min="0"
        max="1"
        step="0.01"
        :value="volumeLevel"
        @input="handleVolumeChange"
        class="flex-1 h-1.5 bg-[#3f75ba] rounded-lg appearance-none cursor-pointer accent-blue-200 hover:accent-blue-100"
      />
    </div>
  </div>
</template>

<script setup>
/* eslint-disable no-undef */
import { ref, onMounted } from 'vue'
import { SpeakerWaveIcon, SpeakerXMarkIcon } from '@heroicons/vue/24/outline'

const isConnected = ref(false)
const volumeLevel = ref(0)
const isMuted = ref(false)

let player = null
let playerController = null
let castInitialized = false
let initializeAttempts = 0
const MAX_INIT_ATTEMPTS = 30 // 30 seconds with 1s intervals

const initCastFramework = () => {
  // If Chrome Cast API is already initialized, skip
  if (castInitialized) {
    return
  }

  // Check if cast API exists
  if (typeof chrome === 'undefined' || !chrome.cast) {
    if (initializeAttempts < MAX_INIT_ATTEMPTS) {
      initializeAttempts++
      setTimeout(initCastFramework, 1000)
    }
    return
  }

  // Initialize the cast framework
  const sessionRequest = new chrome.cast.SessionRequest(chrome.cast.media.DEFAULT_MEDIA_RECEIVER_APP_ID)
  
  const onInitSuccess = () => {
    castInitialized = true
    initRemotePlayer()
  }

  const onInitError = (errorCode) => {
    console.error('Cast initialization error:', errorCode)
  }

  chrome.cast.initialize(sessionRequest, onInitSuccess, onInitError)
}

const initRemotePlayer = () => {
  if (!castInitialized || typeof cast === 'undefined' || !cast.framework) {
    return
  }

  if (player && playerController) {
    // Already initialized
    return
  }

  player = new cast.framework.RemotePlayer()
  playerController = new cast.framework.RemotePlayerController(player)

  playerController.addEventListener(
    cast.framework.RemotePlayerEventType.IS_CONNECTED_CHANGED,
    () => {
      isConnected.value = player.isConnected
    }
  )

  playerController.addEventListener(
    cast.framework.RemotePlayerEventType.VOLUME_LEVEL_CHANGED,
    () => {
      volumeLevel.value = player.volumeLevel
    }
  )

  playerController.addEventListener(
    cast.framework.RemotePlayerEventType.IS_MUTED_CHANGED,
    () => {
      isMuted.value = player.isMuted
    }
  )
  
  // Initial state
  isConnected.value = player.isConnected
  if (player.isConnected) {
    volumeLevel.value = player.volumeLevel
    isMuted.value = player.isMuted
  }
}

const handleVolumeChange = (event) => {
  const newVolume = parseFloat(event.target.value)
  volumeLevel.value = newVolume
  if (player && playerController) {
    player.volumeLevel = newVolume
    playerController.setVolumeLevel()
  }
}

const toggleMute = () => {
  if (player && playerController) {
    playerController.muteOrUnmute()
  }
}

onMounted(() => {
  // Wait for window to be fully loaded before initializing Cast
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      initCastFramework()
    }, { once: true })
  } else {
    initCastFramework()
  }
})
</script>
